namespace Forge.Api.Data.TrainingContent;

public class NotificationsTraining : TrainingContentBase
{
    public NotificationsTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Notifications Overview",
            Slug = "notifications-overview",
            Summary = "What notifications are, how they arrive, the kinds you'll see, their priority levels, and email delivery.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/dashboard"]""",
            Tags = """["notifications","live-updates","email"]""",
            ContentJson = """{"body":"## Notifications Overview\n\nNotifications keep you informed of important events across Forge. They appear the moment something happens, and can also reach you by email — so you never miss a critical update, whether you're at your desk or away.\n\n### How Notifications Arrive\n\nWhen something happens — a job is assigned to you, an expense is overdue, a teammate mentions you — a notification appears right away. The count on the bell icon in the header updates on its own; you don't need to refresh. If your connection drops for a moment, the list catches up as soon as you open it again.\n\n### Kinds of Notifications\n\nEach notification tells you what happened:\n- **Assignment** — a job, task, or responsibility was assigned to you\n- **Overdue** — a job, task, or deadline has passed its due date\n- **Expense** — an expense needs your approval, or was approved or rejected\n- **Maintenance** — an asset changed status or is due for maintenance\n- **System** — background events, such as a sync finishing or a backup completing\n- **Message** — someone sent you a direct message or chat message\n- **Mention** — someone mentioned you in a comment or activity log\n\n### Priority Levels\n\nEach notification has a priority that sets its color and whether it emails you:\n- **Info** (blue) — updates for your awareness, no action needed. For example: a job moved to the next stage, an expense was approved, a sync finished.\n- **Warning** (yellow) — something needs attention soon. For example: a job nearing its due date, a tool nearing the end of its life, an expense waiting for approval for 3 or more days.\n- **Critical** (red) — needs attention right away. For example: an overdue job, a system error, an asset out of service, a failed sync.\n\n### Email Delivery\n\nBesides appearing in the app, notifications can also reach you by email. You choose which kinds email you on the Notifications page, under Preferences:\n- **Critical notifications** — email is on by default (we recommend leaving it on)\n- **Assignment notifications** — email is on by default\n- **Mention notifications** — email is on by default\n\nEach email includes a link that takes you straight to the related record in Forge. Turn each kind of email on or off separately on the Notifications page, under Preferences.\n\n### The Bell Icon\n\nThe bell in the header shows how many notifications you haven't read yet. Click it to open a small panel that slides out, with tabs for All, Messages, and Alerts. Notifications you dismiss disappear from the panel but are kept on record.\n\n### Click to Jump to the Source\n\nMost notifications are more than messages — they're shortcuts. When a notification is about a record (a job, expense, sales order, part, asset, and so on), clicking it marks it read and takes you straight to that record. For example, clicking 'Job #1042 assigned to you' closes the panel and opens that job on the board; clicking an expense notification opens the expense; a shipment notification opens the shipment. It's the fastest way to act — you never have to go hunt for the record. Notifications that aren't tied to a record (general system messages) simply mark themselves read when you click them.\n\n### Sound\n\nA soft chime can play when a new notification arrives. It's on by default and you can turn it off under Preferences. Sound is handy on shop floor displays, where you might not be watching the screen.","sections":[]}"""
        });

        // ── Walkthrough ──────────────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Notifications — Guided Tour",
            Slug = "notifications-walkthrough",
            Summary = "A guided tour of the standalone Notifications page: searching, filtering, bulk actions, and where email/sound preferences live.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/notifications"]""",
            Tags = """["notifications","walkthrough"]""",
            ContentJson = """{"appRoute":"/notifications","startButtonLabel":"Tour Notifications","steps":[{"element":".page-header","popover":{"title":"The Notifications Page","description":"The bell in the header opens a quick pop-out panel. The full Notifications page gives you your complete history, with search, filtering, sorting, and your settings. It has two tabs: All Notifications and Preferences.","side":"bottom"}},{"element":".tab-bar","popover":{"title":"All Notifications and Preferences","description":"Switch between the two tabs here. All Notifications lists everything you've received, ready to search and sort. Preferences is where you set up email and sound. Your email settings live here, on this page — not in the header menu.","side":"bottom"}},{"element":".toolbar","popover":{"title":"Search, Filter, and Bulk Actions","description":"On the All Notifications tab, type in Search to find text in a notification. Narrow the list by priority (Info, Warning, or Critical) or by where it came from. On the right, Mark All Read clears your unread count and Dismiss All empties the list. Click a column heading to sort.","side":"bottom"}},{"element":"app-data-table","popover":{"title":"The Notification List","description":"Every notification you haven't dismissed shows here, with its title, message, priority, source, and date. Click a column heading to sort; click again to reverse. This is your full history — nothing is trimmed to a recent few, unlike the quick bell panel.","side":"top"}},{"element":".tab-bar","popover":{"title":"Set Your Preferences","description":"Click the Preferences tab to choose how you're notified. Under email, turn Critical Alerts, Job Assignments, and Mentions on or off (all on by default). Under in-app, turn Sound on or off — off for quiet offices, on for shop-floor displays. Each row is a simple on/off switch.","side":"bottom"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Notifications Field Reference",
            Slug = "notifications-field-reference",
            Summary = "Complete reference for notification fields, severity levels, types, panel controls, preferences, actions, and filtering.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/dashboard"]""",
            Tags = """["notifications","reference"]""",
            ContentJson = """{"title":"Notifications Field Reference","groups":[{"heading":"Notification Fields","items":[{"label":"Title","value":"A short summary of what happened. Shown in bold until you read it. For example: 'Job #1042 assigned to you' or 'Expense approved'."},{"label":"Message","value":"The fuller description, with more detail than the title. For example: 'Hartman, Daniel J assigned Job #1042 — CNC Bracket Assembly to you' or 'Your $245.00 travel expense was approved by Smith, Jane A'."},{"label":"Kind","value":"What the notification is about — an assignment, overdue item, expense, maintenance, system event, message, or mention. Helps you filter the list."},{"label":"Priority","value":"How urgent it is: Info (blue) for your awareness, Warning (yellow) when something needs attention soon, Critical (red) when it needs action right away. Priority sets the color stripe and whether it emails you."},{"label":"Source","value":"Where it came from: a person (a message, mention, or assignment) or the system (an overdue alert, sync event, or maintenance warning)."},{"label":"Read","value":"Whether you've read it. Unread notifications show a bold title and add to the count on the bell. Reading one removes the bold and lowers the count."},{"label":"Pinned","value":"Whether it's pinned. Pinned notifications stay at the top of the list no matter their date — handy for keeping important items in view. You can pin or unpin any notification."},{"label":"Dismissed","value":"Whether it's been dismissed. Dismissed notifications disappear from the list but are kept on record. They don't show in any tab or filter, and can't be brought back from the panel."},{"label":"Related Record","value":"The kind of record a notification is about, such as a job, expense, asset, or part. When set, clicking the notification opens that record."},{"label":"Which Record","value":"Which specific record it points to. Together with the kind of record, this is what makes clicking the notification jump straight there."},{"label":"Sender Initials","value":"For notifications from a person, their initials, shown in a small colored circle so you can tell at a glance who it's from."},{"label":"Sender Color","value":"The color of that sender's circle. It matches the color assigned to them in the system."},{"label":"Created","value":"When the notification arrived. The panel shows it as a relative time ('5 min ago', '2 hours ago'); the full list shows the date and time."}]},{"heading":"Priority Levels","items":[{"label":"Info (blue stripe)","value":"For your awareness — no action needed. For example: a job moved to the next stage, an expense approved, a file uploaded, a sync finished. Email is off by default."},{"label":"Warning (yellow stripe)","value":"Needs attention soon. For example: a job nearing its due date, a tool nearing the end of its life, an expense waiting for approval 3 or more days. Email is off by default."},{"label":"Critical (red stripe)","value":"Needs action right away. For example: an overdue job, a system error, an asset out of service, a failed sync, a security alert. Email is on by default."}]},{"heading":"Kinds of Notification","items":[{"label":"Assignment","value":"Arrives when a job, task, or responsibility is assigned to you. Comes from a person. Email is on by default."},{"label":"Overdue","value":"Arrives when a job, task, or deadline passes its due date. Comes from the system, usually as a warning or critical."},{"label":"Expense","value":"Arrives for expense approval requests, approvals, and rejections. Comes from a person or the system, depending on the action."},{"label":"Maintenance","value":"Arrives when an asset goes into maintenance or out of service, or when scheduled maintenance is due. Comes from the system."},{"label":"System","value":"Background events, such as a backup finishing, a sync status, a scheduled task result, or a settings change. Comes from the system."},{"label":"Message","value":"Arrives when someone sends you a direct message or chat message. Comes from a person, and shows their initials."},{"label":"Mention","value":"Arrives when someone mentions you in a comment, activity log, or chat message. Comes from a person. Email is on by default."}]},{"heading":"Panel Tabs","items":[{"label":"All","value":"Shows every notification you haven't dismissed, from any source. This is the tab you see when the panel opens."},{"label":"Messages","value":"Shows only notifications from people — direct messages, chat messages, mentions, and assignments from teammates."},{"label":"Alerts","value":"Shows only notifications from the system — overdue warnings, maintenance alerts, sync events, and other automatic notices."}]},{"heading":"What You Can Do","items":[{"label":"Click to open the record","value":"Clicking a notification marks it read and, if it's about a record, takes you straight there. A job opens on the board; an expense opens the expense; and the same for sales orders, purchase orders, invoices, parts, shipments, customers, assets, vendors, leads, payments, and returns. Notifications not tied to a record just mark themselves read."},{"label":"Mark as read","value":"Click a notification to mark it read. Its title stops being bold and the unread count drops by one. The change appears at once and is saved for you."},{"label":"Pin or unpin","value":"Pin a notification to keep it at the top of the list no matter its date. Handy for tracking an ongoing issue. Unpin it when you're done."},{"label":"Dismiss","value":"Hide a single notification from the panel. It's marked dismissed and drops out of every view, but is kept on record."},{"label":"Mark All Read","value":"Mark every notification read in one click. The unread count drops to zero. This covers all notifications, not just the current tab."},{"label":"Dismiss All","value":"Dismiss every notification showing and empty the panel. Dismissed items are hidden but kept on record."}]},{"heading":"Notification Preferences","items":[{"label":"Email on Critical","value":"When on, critical notifications also reach you by email. On by default. Found on the Notifications page, under Preferences."},{"label":"Email on Assignment","value":"When on, assignment notifications reach you by email. On by default — useful for staying in the loop when you're away."},{"label":"Email on Mention","value":"When on, mentions reach you by email. On by default, so you catch them even when you're not in the app."},{"label":"Sound","value":"When on, a chime plays as each new notification arrives. On by default. Turn it off for quiet spaces."}]},{"heading":"Filtering the List","items":[{"label":"Search","value":"Type to find text in a notification's title or message. The list narrows as you type."},{"label":"Priority","value":"Pick All, Info, Warning, or Critical to show only notifications of that priority."},{"label":"Source","value":"Filter by where a notification came from — a person or the system."}]},{"heading":"List Columns","items":[{"label":"Title","value":"The short summary. Click the heading to sort by it."},{"label":"Message","value":"The fuller description. Click the heading to sort by it."},{"label":"Priority","value":"Info, Warning, or Critical, shown by color. Sort or filter by it."},{"label":"Source","value":"Whether the notification came from a person or the system. Click the heading to sort by it."},{"label":"Date","value":"When the notification arrived. Click the heading to sort by it."}]},{"heading":"Staying Up to Date","items":[{"label":"Live updates","value":"New notifications appear on their own, and the bell count updates without a refresh."},{"label":"A new one arrives","value":"The moment something happens, the notification shows up in the panel and, if sound is on, a chime plays."},{"label":"After a dropped connection","value":"If your connection drops for a bit, the list catches up when you open the panel again, so nothing is missed. A banner shows yellow while reconnecting and red while disconnected."},{"label":"Always on","value":"Live updates start on their own once you sign in — there's nothing to turn on, on any page."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Notifications Knowledge Check",
            Slug = "notifications-quiz",
            Summary = "Test your knowledge of the notification system: types, severity, panel actions, preferences, and live delivery.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/dashboard"]""",
            Tags = """["notifications","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"notif1","text":"You see a red circle with the number 3 on the bell in the header. What does this mean?","options":[{"id":"a","text":"There are 3 critical notifications waiting"},{"id":"b","text":"You have 3 unread notifications, of any kind or priority","isCorrect":true},{"id":"c","text":"There are 3 new notifications from the last hour"},{"id":"d","text":"There are 3 pinned notifications in your panel"}],"explanation":"The number on the bell counts all your unread notifications, whatever their kind or priority. It updates on its own as new ones arrive or as you read the ones you have."},{"id":"notif2","text":"You want to see only the system's own alerts (overdue warnings, sync events) and hide messages from other people. Which tab do you pick?","options":[{"id":"a","text":"All — then scan through for the system ones yourself"},{"id":"b","text":"Messages — system alerts show up as messages"},{"id":"c","text":"Alerts — this tab shows only notifications from the system","isCorrect":true},{"id":"d","text":"There's no way to filter by source in the panel"}],"explanation":"The Alerts tab shows only notifications from the system. The Messages tab shows notifications from people (direct messages, mentions, assignments). The All tab shows everything."},{"id":"notif3","text":"A notification has a yellow stripe down its side in the panel. What priority does this show?","options":[{"id":"a","text":"Info — a general update for your awareness"},{"id":"b","text":"Warning — something needs attention soon","isCorrect":true},{"id":"c","text":"Critical — needs action right away"},{"id":"d","text":"Pinned — the notification has been pinned to the top"}],"explanation":"A yellow stripe means Warning — something needs attention soon but isn't yet urgent. Blue is Info (for your awareness), red is Critical (act right away). The stripe color has nothing to do with pinning."},{"id":"notif4","text":"You dismiss all notifications with the Dismiss All button. Can these notifications be brought back?","options":[{"id":"a","text":"No — dismissed notifications are deleted for good"},{"id":"b","text":"Yes — dismissed notifications are hidden from the panel but kept on record","isCorrect":true},{"id":"c","text":"Only if you undo within 10 seconds using the pop-up prompt"},{"id":"d","text":"Only admins can recover dismissed notifications from a trash bin"}],"explanation":"Dismissed notifications are hidden from the panel, but they're never deleted — they're kept on record. There's just no button in the panel to bring them back yourself."},{"id":"notif5","text":"You want an important notification to stay at the top of your panel, no matter when it arrived. How do you do this?","options":[{"id":"a","text":"Mark it critical to force it to the top"},{"id":"b","text":"Pin it — pinned notifications always sort above the rest","isCorrect":true},{"id":"c","text":"Star it using the star icon"},{"id":"d","text":"Move it to the Messages tab so it gets priority"}],"explanation":"Pinning a notification keeps it at the top of the list, above everything else, no matter its date. You can pin and unpin any notification."},{"id":"notif6","text":"Which notification setting is on by default so you get emails for the most urgent events?","options":[{"id":"a","text":"Email on every notification, whatever its priority"},{"id":"b","text":"Email on Critical notifications","isCorrect":true},{"id":"c","text":"Email on Warning and Critical notifications"},{"id":"d","text":"No email settings are on by default"}],"explanation":"Email on Critical is on by default because critical notifications need action right away (overdue jobs, system errors, asset failures). Email on Assignment and Email on Mention are also on by default. Info and warning notifications don't email you by default."},{"id":"notif7","text":"You're working on the shop floor and not looking at the screen. How does Forge let you know a new notification arrived?","options":[{"id":"a","text":"The screen flashes red for critical notifications"},{"id":"b","text":"A chime plays when a notification arrives, if Sound is on","isCorrect":true},{"id":"c","text":"It sends a text message to your phone"},{"id":"d","text":"There's no way to be alerted without watching the screen"}],"explanation":"When Sound is on (the default), a chime plays each time a new notification arrives. This is handy on shop floor displays. You can turn it off under Preferences if you prefer quiet."},{"id":"notif8","text":"Your connection dropped for 2 minutes. When it comes back, how does Forge make sure you didn't miss any notifications?","options":[{"id":"a","text":"It automatically replays every missed one from a stored backup"},{"id":"b","text":"When you open the notification panel, it refreshes the full list so anything missed during the drop shows up","isCorrect":true},{"id":"c","text":"Missed notifications are lost for good and must be checked by email"},{"id":"d","text":"It sends one email with all the missed notifications after reconnecting"}],"explanation":"Opening the notification panel refreshes the full list, so any notification created while you were disconnected appears. A banner also shows yellow while reconnecting and red while disconnected, so you know live updates are paused."},{"id":"notif9","text":"A colleague mentions you in a comment on a job's activity log. What kind and source will the notification have?","options":[{"id":"a","text":"Kind: Mention, Source: a person","isCorrect":true},{"id":"b","text":"Kind: Message, Source: the system"},{"id":"c","text":"Kind: Assignment, Source: a person"},{"id":"d","text":"Kind: System, Source: a person"}],"explanation":"A mention from a colleague creates a Mention notification from a person. It shows under the Messages tab, and if Email on Mention is on, you'll get an email too."},{"id":"notif10","text":"You click Mark All Read in the notification panel. Which of these is true?","options":[{"id":"a","text":"Only notifications in the tab you're on are marked read"},{"id":"b","text":"Every notification is marked read, the unread count drops to zero, and the change is saved for you","isCorrect":true},{"id":"c","text":"Every notification is dismissed and removed from the panel"},{"id":"d","text":"Only unread notifications from the last 24 hours are marked read"}],"explanation":"Mark All Read marks every notification read, not just the ones in the current tab. The unread count drops to zero right away and the change is saved for you. The notifications stay in the panel — they're not dismissed."}]}"""
        });

        // ── Advanced Reference (Reference) ───────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Notifications — Advanced Reference",
            Slug = "notifications-reference",
            Summary = "The finer points: where each kind of notification takes you, notifications on your phone, when notifications are turned on, and what happens to dismissed ones.",
            ContentType = TrainingContentType.Reference,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 90,
            AppRoutes = """["/dashboard"]""",
            Tags = """["notifications","reference","advanced"]""",
            ContentJson = """{"body":"## Where a Notification Takes You\n\nWhen a notification is about a record, clicking it marks it read and opens that record. Here's where each kind of notification takes you:\n\n| Notification about a | Opens |\n|---|---|\n| Job | the job on the board |\n| Quote | the quote |\n| Sales order | the sales order |\n| Purchase order | the purchase order |\n| Invoice | the invoice |\n| Expense | the expense |\n| Lead | the lead |\n| Part | the part |\n| Shipment | the shipment |\n| Customer | the customer's overview |\n| Asset | the asset |\n| Vendor | the vendor |\n| Time entry | time tracking |\n| Customer return | the customer return |\n| Payment | the payment |\n| Training | the training page |\n| User | the users admin page |\n| Tax form | your tax forms |\n| Reorder suggestion | inventory replenishment |\n\nA notification that isn't tied to a record still marks itself read when you click it — it just doesn't open anything.\n\n## Notifications on Your Phone\n\nOn a phone, notifications get their own simple screen, separate from the bell panel and the full Notifications page. It shows the same notifications and lets you dismiss them one at a time. It's a lighter, touch-friendly view — for full search, sorting, and your preferences, open the full Notifications page.\n\n## When Notifications Are Turned On\n\nNotifications can be turned on or off for your whole workspace by an administrator. When they're on, the bell and the Notifications page work as described. When they're off, the bell panel and the Notifications page show nothing. If you expect notifications and don't see any, check with your administrator.\n\n## What Happens to Dismissed Notifications\n\nDismissing a notification hides it — it doesn't delete it. Whether you dismiss one at a time or use Dismiss All, the notifications drop out of every tab and the full list, but they're kept on record and never truly removed. There's no button to bring a dismissed notification back yourself. Marking notifications read or pinning them works the same way: each change is saved for you, notification by notification.","sections":[]}"""
        });

        Log.Information("Seeded Notifications training modules");
    }
}
